## sqlx（type-safe DB）
```rust
use sqlx::PgPool;

#[derive(sqlx::FromRow, Serialize)]
struct User { id: i32, name: String }

async fn users(State(pool): State<PgPool>) -> Json<Vec<User>> {
    let users: Vec<User> = sqlx::query_as!(User, "SELECT id, name FROM users")
        .fetch_all(&pool)
        .await
        .unwrap();
    Json(users)
}
